+#[fcp_async_core::runtime::test]
+async fn semanticscholar_default_deny_compliance_suite_passes() {
+    let mock = MockApiServer::start().await;
+
+    let mut connector = SemanticScholarConnectorAdapter::new();
+    let signing_key = Ed25519SigningKey::generate();
+    let handshake = handshake_request(
+        signing_key.verifying_key().to_bytes(),
+        &["semanticscholar.papers.read"],
+    );
+    let token = build_token(
+        &signing_key,
+        "semanticscholar.papers.read",
+        &["semanticscholar.paper.search"],
+    );
+    let invoke = invoke_request(
+        "semanticscholar.paper.references",
+        json!({ "paper_id": "649def34f8be52c8b66281af98ae884c09aef38b" }),
+        token,
+    );
+
+    let dynamic = DynamicSuite {
+        config: semanticscholar_config(&mock.base_url()),
+        handshake,
+        invoke: Some(invoke),
+        expect_invoke_error: true,
+        simulate: None,
+        expect_simulate_would_succeed: None,
+        require_simulate_denial_details: false,
+        require_capability_denial: true,
+        require_decision_receipt: false,
+    };
+    let suite = ComplianceSuite::new(
+        "semanticscholar_default_deny",
+        semanticscholar_manifest_with_hash(),
+        dynamic,
+    );
+
+    let mut runner = E2eRunner::new("fcp-e2e-semanticscholar");
+    let report = runner
+        .run_compliance_suite(&mut connector, suite)
+        .await
+        .expect("compliance suite run");
+
+    assert!(report.passed, "default deny compliance should pass");
+}
+
+#[fcp_async_core::runtime::test]
+async fn semanticscholar_allow_valid_token_connector_suite_passes() {
+    let mock = MockApiServer::start().await;
+
+    Mock::given(method("GET"))
+        .and(path("/paper/search"))
+        .and(query_param("query", "attention mechanism"))
+        .and(header("x-api-key", "semanticscholar-test-api-key"))
+        .respond_with(ResponseTemplate::new(200).set_body_json(paper_search_response()))
+        .mount(mock.inner())
+        .await;
+
+    let mut connector = SemanticScholarConnectorAdapter::new();
+    let signing_key = Ed25519SigningKey::generate();
+    let handshake = handshake_request(
+        signing_key.verifying_key().to_bytes(),
+        &["semanticscholar.papers.read"],
+    );
+    let token = build_token(
+        &signing_key,
+        "semanticscholar.papers.read",
+        &["semanticscholar.paper.search"],
+    );
+    let invoke = invoke_request(
+        "semanticscholar.paper.search",
+        json!({ "query": "attention mechanism" }),
+        token,
+    );
+    let suite = ConnectorSuite {
+        test_name: "semanticscholar_allow_valid_token".to_string(),
+        config: semanticscholar_config(&mock.base_url()),
+        handshake,
+        invoke: Some(invoke),
+        invoke_expectations: InvokeExpectations {
+            expect_error: false,
+            expect_decision_receipt: false,
+            expect_audit_event: false,
+            expect_receipt: false,
+            expected_reason_code: None,
+            rate_limit_pool: None,
+        },
+    };
+
+    let mut runner = E2eRunner::new("fcp-e2e-semanticscholar");
+    let report = runner
+        .run_connector_suite(&mut connector, suite)
+        .await
+        .expect("connector suite run");
+
+    assert!(report.passed, "allow suite should pass");
+    let invoke_entry = report
+        .logs
+        .iter()
+        .find(|entry| entry.context.get("operation") == Some(&json!("invoke")))
+        .expect("invoke entry");
+    assert_eq!(invoke_entry.result, "pass");
+    assert_eq!(
+        invoke_entry.context.get("invoke_status"),
+        Some(&json!(format!("{:?}", InvokeStatus::Ok)))
+    );
+}
+
+#[test]
+fn semanticscholar_manifest_network_guard_allows_and_denies() {
+    let manifest = semanticscholar_manifest_toml();
+    let operations = manifest
+        .get("provides")
+        .and_then(toml::Value::as_table)
+        .and_then(|provides| provides.get("operations"))
+        .and_then(toml::Value::as_table)
+        .expect("operations table");
+
+    assert_eq!(
+        operations.len(),
+        7,
+        "Semantic Scholar manifest should declare 7 operations"
+    );
+
+    let expected_hosts = vec!["api.semanticscholar.org".to_string()];
+
+    for operation_name in operations.keys() {
+        let host_allow = operation_host_allow_list(&manifest, operation_name);
+        assert_eq!(
+            host_allow, expected_hosts,
+            "operation {operation_name} should use exact Semantic Scholar API host allowlist"
+        );
+
+        assert!(host_allowed("api.semanticscholar.org", &host_allow));
+        assert!(!host_allowed("semanticscholar.org", &host_allow));
+        assert!(!host_allowed("evil.api.semanticscholar.org", &host_allow));
+        assert!(!host_allowed("example.com", &host_allow));
+        assert!(!host_allowed("127.0.0.1", &host_allow));
+
+        let constraints = operation_network_constraints(&manifest, operation_name);
+        assert_eq!(
+            constraints
+                .get("deny_localhost")
+                .and_then(toml::Value::as_bool),
+            Some(true),
+            "operation {operation_name} must deny localhost"
+        );
+        assert_eq!(
+            constraints
+                .get("deny_private_ranges")
+                .and_then(toml::Value::as_bool),
+            Some(true),
+            "operation {operation_name} must deny private ranges"
+        );
+        assert_eq!(
+            constraints
+                .get("require_sni")
+                .and_then(toml::Value::as_bool),
+            Some(true),
+            "operation {operation_name} must require SNI"
+        );
+    }
+}
